+function delegationInput(input: unknown): { agentId?: string; instructions?: string } {
+  if (!input || typeof input !== "object") return {};
+  const value = input as Record<string, unknown>;
+  return {
+    agentId: typeof value.agent_id === "string" ? value.agent_id : undefined,
+    instructions: typeof value.instructions === "string" ? value.instructions : undefined,
+  };
+}
+
+function toolUseId(response: ProviderResponse): string {
+  // Providers that do not expose a model-assigned ID still need a stable ID for
+  // the tool_use/tool_result pair within this streamed turn.
+  return response.toolUseId || `delegate-${crypto.randomUUID()}`;
+}
+
+function toolUseResponse(response: ProviderResponse, id: string): StreamResponse {
+  return {
+    type: "claude_json",
